define(['core/str'], function(Str) {
    return {
        init: function(timeCreated, minTimeMins, minAnsweredPct, serverTimeAtLoad) {
            const minTimeSecs = minTimeMins * 60;
            const localTimeAtLoad = Math.floor(Date.now() / 1000);

            const getRemaining = () => {
                if (minTimeSecs <= 0) return 0;
                const elapsedSinceLoad = Math.floor(Date.now() / 1000) - localTimeAtLoad;
                const approxServerTime = serverTimeAtLoad + elapsedSinceLoad;
                return minTimeSecs - (approxServerTime - timeCreated);
            };

            const getAnsweredPercent = () => {
                const qnButtons = document.querySelectorAll('.qnbutton, a.qnbutton, div.qnbutton');
                if (qnButtons.length > 0) {
                    let answered = 0;
                    qnButtons.forEach(btn => {
                        if (btn.classList.contains('answersaved') || btn.classList.contains('requiresgrading') || btn.classList.contains('answered')) {
                            answered++;
                        }
                    });
                    return (answered / qnButtons.length) * 100;
                }
                const summaryRows = document.querySelectorAll('table.quizsummaryofattempt tbody tr');
                if (summaryRows.length > 0) {
                    let answered = 0;
                    summaryRows.forEach(row => {
                        const text = (row.textContent || '').toLowerCase();
                        if (text.includes('saved') || text.includes('answered') || text.includes('tersimpan') || text.includes('disimpan') || text.includes('diisi') || text.includes('menjawab') || text.includes('grading')) {
                            answered++;
                        }
                    });
                    return (answered / summaryRows.length) * 100;
                }
                return document.querySelectorAll('.que').length > 0 ? 0 : 100;
            };

            const msebStyle = document.createElement('style');
            msebStyle.id = 'mseb-sledgehammer';
            msebStyle.textContent = 'form:not(#responseform)[action*="processattempt.php"] { display: none !important; opacity: 0 !important; visibility: hidden !important; pointer-events: none !important; margin: 0 !important; padding: 0 !important; border: 0 !important; width: 0 !important; height: 0 !important; overflow: hidden !important; position: absolute !important; left: -9999px !important; } a[href*="summary.php"] { display: none !important; pointer-events: none !important; visibility: hidden !important; } .endtestlink { display: none !important; pointer-events: none !important; visibility: hidden !important; } input[name="next"][value*="Selesai"], input[name="next"][value*="selesai"], input[name="next"][value*="Finish"], input[name="next"][value*="finish"] { display: none !important; pointer-events: none !important; visibility: hidden !important; }';

            if (minTimeSecs > 0 || minAnsweredPct > 0) {
                document.head.appendChild(msebStyle);
            }

            window.addEventListener('submit', async (e) => {
                if (getRemaining() > 0 || getAnsweredPercent() < minAnsweredPct) {
                    const f = e.target;
                    let isFinishAttempt = false;
                    if (f.action && f.action.includes('processattempt.php')) {
                        if (f.id !== 'responseform') isFinishAttempt = true;
                        if (e.submitter && (e.submitter.name.includes('finish') || (e.submitter.value && e.submitter.value.toLowerCase().includes('selesai')))) isFinishAttempt = true;
                        if (f.querySelector('input[name="finishattempt"]')) isFinishAttempt = true;
                    }
                    if (isFinishAttempt) {
                        e.preventDefault();
                        e.stopPropagation();
                        e.stopImmediatePropagation();
                    }
                }
            }, true);

            document.addEventListener('click', (e) => {
                if (getRemaining() > 0 || getAnsweredPercent() < minAnsweredPct) {
                    const t = e.target;
                    if (t.closest('a[href*="summary.php"]') || t.closest('.endtestlink')) {
                        e.preventDefault(); e.stopPropagation();
                    }
                }
            }, true);

            document.addEventListener('DOMContentLoaded', () => {
                const tick = () => {
                    const timeMet = getRemaining() <= 0;
                    const answeredMet = getAnsweredPercent() >= minAnsweredPct;
                    if (!timeMet || !answeredMet) {
                        if (!document.getElementById('mseb-sledgehammer') && (minTimeSecs > 0 || minAnsweredPct > 0)) document.head.appendChild(msebStyle);
                    } else {
                        const lock = document.getElementById('mseb-sledgehammer');
                        if (lock) lock.remove();
                    }
                };
                setInterval(tick, 1000);
                tick();
            });
        }
    };
});
